Script:
{
  "name": "Scenario1",
  "cron": "",
  "period": 100,
  "code": "
    last_state := 'closed'
    door_state = (#entrance #DoorLock).doorControl_door
    if (door_state != last_state) {
      if (door_state == 'open') {
        (#entrance #Light).switch_on()
      }
      last_state = door_state
    }
  "
}
